let hls: Hls | null = null;

function readStoredList(key: string) {
  try {
    const raw = localStorage.getItem(`yingshi:${key}`);
    const parsed = raw ? JSON.parse(raw) : [];
    return Array.isArray(parsed) ? parsed.map(String) : [];
  } catch {
    return [];
  }
}

function storeList(key: string, values: string[]) {
  localStorage.setItem(`yingshi:${key}`, JSON.stringify(values));
}

function escapeHtml(value: unknown) {
  return String(value ?? '')
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#039;');
}

function titleInitials(title: string) {
  return [...title.replace(/\s+/g, '')].slice(0, 2).join('') || '影視';
}

async function getJson<T>(url: string, fallback: T): Promise<T> {
  try {
    const response = await fetch(url, { cache: 'no-store' });
    if (!response.ok) {
      return fallback;
    }
    return (await response.json()) as T;
  } catch {
    return fallback;
  }
}

async function bootstrap() {
  const [vodSources, liveChannels, summary] = await Promise.all([
    getJson<VodSource[]>('/data/vod-sources.json', []),
    getJson<LiveChannel[]>('/data/live-channels.json', []),
    getJson<SourceSummary>('/data/source-summary.json', emptySummary),
  ]);

  state.vodSources = vodSources;
  state.liveChannels = liveChannels;
  state.summary = summary;
  render();

  if ('serviceWorker' in navigator) {
    navigator.serviceWorker.register('/sw.js').catch(() => undefined);
  }
}

function render() {
  app.innerHTML = `
    <div class="app-shell">
      ${renderHeader()}
      <main class="screen">${renderActiveScreen()}</main>
      ${renderBottomTabs()}
      ${renderPlayer()}
    </div>
  `;

  bindEvents();
  createIcons({ icons: lucideIcons });
  if (state.playerOpen && state.playerUrl) {
    void attachPlayer(state.playerUrl);
  }
}

