function renderVodSourceRow(source: VodSource) {
  const categories = source.categories.slice(0, 4).map((item) => `<span>${escapeHtml(item)}</span>`).join('');
  return `
    <article class="source-row">
      <div class="source-main">
        <div class="source-icon">${escapeHtml(source.typeLabel.slice(0, 2))}</div>
        <div>
          <strong>${escapeHtml(source.name)}</strong>
          <span>${escapeHtml(source.typeLabel)} · ${source.searchable ? '可搜尋' : '不可搜尋'} · ${source.quickSearch ? '快搜' : '標準'}</span>
        </div>
      </div>
      <div class="category-strip">${categories || '<span>未分類</span>'}</div>
      <div class="source-status">
        <span class="status-badge">需授權</span>
        <small>${escapeHtml(source.endpointHost || source.origin)}</small>
      </div>
    </article>
  `;
}

function renderLiveChannel(channel: LiveChannel) {
  const icon = channel.kind === 'external' ? 'external-link' : channel.playable ? 'play' : 'lock';
  const action = channel.kind === 'external' ? '外部' : channel.playable ? '播放' : '不可播';
  return `
    <article class="channel-row">
      <button class="channel-main" type="button" data-live-channel="${channel.id}" ${channel.playable || channel.kind === 'external' ? '' : 'disabled'}>
        <div class="channel-avatar">${escapeHtml(titleInitials(channel.name))}</div>
        <div>
          <strong>${escapeHtml(channel.name)}</strong>
          <span>${escapeHtml(channel.group)} · ${kindLabel(channel.kind)}</span>
        </div>
      </button>
      <button class="icon-text-btn ${channel.playable || channel.kind === 'external' ? '' : 'is-disabled'}" type="button" data-live-channel="${channel.id}" ${channel.playable || channel.kind === 'external' ? '' : 'disabled'}>
        <i data-lucide="${icon}"></i>
        ${action}
      </button>
    </article>
  `;
}

function renderProtocolRows() {
  const counts = state.liveChannels.reduce<Record<string, number>>((acc, channel) => {
    acc[channel.kind] = (acc[channel.kind] || 0) + 1;
    return acc;
  }, {});

  return ['hls', 'stream', 'external', 'network', 'unknown']
    .map(
      (kind) => `
        <div class="type-row">
          <span>${kindLabel(kind)}</span>
          <strong>${counts[kind] || 0}</strong>
        </div>
      `,
    )
    .join('');
}

